sql:
SELECT u.user_name, q.question_text, q.review_status
FROM questions q
JOIN users u ON q.created_by = u.user_id;

SELECT u.user_name, u.email
FROM users u
WHERE u.role = 'student' AND u.user_id IN (
  SELECT DISTINCT sr.user_id
  FROM student_responses sr
);

external_knowledge:
- Initial subject refers to subject_id = 1;
- Inquiries represent questions;
- Tests mean assessments;

sql:
SELECT user_name, email, role, status
FROM users
WHERE user_id IN (SELECT DISTINCT last_reviewed_by FROM questions WHERE last_reviewed_by IS NOT NULL);

SELECT question_text, media_url
FROM questions
WHERE question_id = 1;

SELECT DISTINCT user_name
FROM users
WHERE user_id IN (SELECT DISTINCT created_by FROM questions);

SELECT selected_option_id, response_time, feedback
FROM student_responses
WHERE user_id = 0 AND question_id = 1;

external_knowledge:
- 'top performances' refers to the assessments where the total score achieved by a user is the highest among all their assessments;
- The 'percentage' refers to the percentage score achieved by the user in the respective assessment;
- 'submission times' indicate the timestamp when the assessments were submitted.

sql:
SELECT AVG(total_score) AS Average_Score
FROM assessment_scores
WHERE user_id = (SELECT user_id FROM users WHERE user_name = 'Bob Williams');

SELECT assessment_id, total_score
FROM assessment_scores
WHERE total_score > 80 AND review_status != 'Approved';
